-- CAMISETAS

ALTER TABLE usuarios AUTO_INCREMENT = 2000;
ALTER TABLE ligas AUTO_INCREMENT = 2000;
ALTER TABLE equipos AUTO_INCREMENT = 2000;
ALTER TABLE camisetas AUTO_INCREMENT = 2000;
ALTER TABLE pedidos AUTO_INCREMENT = 2000;
ALTER TABLE pedido_items AUTO_INCREMENT = 2000;

-- Ventas iniciales de ejemplo (la popularidad sube con cada compra real)
UPDATE camisetas SET ventas = MOD(id * 37 + 13, 200);
UPDATE camisetas SET ventas = ventas + 300 WHERE destacado = TRUE;

-- Precios variados entre 20 y 25 euros (cifras redondas)
UPDATE camisetas SET precio = 20 + MOD(id * 7, 6);

-- Quitamos las camisetas retro del catalogo
DELETE FROM camisetas WHERE coleccion = 'retro';

-- Pedidos de ejemplo (para que las tablas pedidos y pedido_items no esten vacias)


ALTER TABLE pedidos AUTO_INCREMENT = 2000;
